from fastapi import APIRouter
from pydantic import BaseModel

todo_router = APIRouter(tags=['todos'])

todos = []

class TodoCreate(BaseModel):
    text: str

@todo_router.get('/')
def list_todos():
    return todos

@todo_router.post('/', status_code=201)
def create_todo(todo: TodoCreate):
    new_todo = {'id': len(todos) + 1, 'text': todo.text}
    todos.append(new_todo)
    return new_todo

from fastapi import FastAPI

app = FastAPI()

todos = [{'id': i, 'text': f'Todo {i}'} for i in range(1, 101)]

@app.get('/todos')
def list_todos(skip: int = 0, limit: int = 20):
    limit = min(limit, 100)
    return {
        'total': len(todos),
        'skip': skip,
        'limit': limit,
        'items': todos[skip : skip + limit]
    }

import json
import redis
from fastapi import FastAPI

app = FastAPI()

r = redis.Redis(host='localhost', port=6379, decode_responses=True)

@app.get('/todos')
def list_todos():
    cached = r.get('todos:all')
    if cached:
        return json.loads(cached)

    todos = [{'id': 1, 'text': 'Example todo'}]
    r.setex('todos:all', 300, json.dumps(todos))
    return todos

import os
import sentry_sdk
from fastapi import FastAPI

sentry_sdk.init(
    dsn=os.environ['SENTRY_DSN'],
    traces_sample_rate=1.0,
)

app = FastAPI()

@app.post('/orders')
def create_order(user_id: int, item: str):
    sentry_sdk.set_user({'id': user_id})
    sentry_sdk.set_extra('item', item)
    return {'status': 'ok', 'user_id': user_id, 'item': item}
